  var tailscaleCheckbox = document.getElementById("sandbox_tailscale");
  var dockerCheckbox = document.getElementById("sandbox_docker_enabled");
  var oidcCheckbox = document.getElementById("sandbox_oidc_enabled");
  var gcpCheckbox = document.getElementById("sandbox_gcp_oidc_enabled");
  var gcpConfigSelect = document.getElementById("sandbox_gcp_oidc_config_id");
  var gcpServiceAccountInput = document.getElementById("sandbox_gcp_service_account_email");
  var gcpPrincipalScopeSelect = document.getElementById("sandbox_gcp_principal_scope");
  var gcpRolesInput = document.getElementById("sandbox_gcp_roles_text");
  var sshStartTmuxCheckbox = document.getElementById("sandbox_ssh_start_tmux");
  var smbCheckbox = document.getElementById("sandbox_smb_enabled");
  var vncGeometrySelect = document.getElementById("sandbox_vnc_geometry");
  var vncDepthSelect = document.getElementById("sandbox_vnc_depth");
  var projectPresetMode = false;
  var toggleDataPath = function() {};
  var toggleHomePath = function() {};
  var syncProjectMode = function() {};
  var applyCheckbox = function(element, value) {
    if (element && !element.disabled) {
      element.checked = !!value;
    }
  };
  var applyValue = function(element, value) {
    if (element) {
      element.value = value == null ? "" : String(value);
    }
  };
  var applySelectValue = function(element, value) {
    if (!element) return;

    var normalized = value == null ? "" : String(value);
    var hasOption = Array.prototype.some.call(element.options, function(option) {
      return option.value === normalized;
    });
    element.value = hasOption ? normalized : "";
  };
  var applyProjectDefaults = function() {
    if (!projectSelect) return;

    var defaults = projectDefaults[projectSelect.value];
    if (!defaults) return;

    applyValue(imageInput, defaults.image);
    applyCheckbox(mountHomeCheckbox, defaults.mount_home);
    applyValue(homePathInput, defaults.home_path);
    applyCheckbox(mountDataCheckbox, defaults.data_path !== null && defaults.data_path !== "");
    applyValue(dataPathInput, defaults.data_path === "." ? "" : defaults.data_path);
    applyCheckbox(tailscaleCheckbox, defaults.tailscale);
    applyCheckbox(dockerCheckbox, defaults.docker_enabled);
    applyCheckbox(oidcCheckbox, defaults.oidc_enabled || defaults.gcp_oidc_enabled);
    applyCheckbox(gcpCheckbox, defaults.gcp_oidc_enabled);
    applySelectValue(gcpConfigSelect, defaults.gcp_oidc_config_id);
    applyValue(gcpServiceAccountInput, defaults.gcp_service_account_email);
    applySelectValue(gcpPrincipalScopeSelect, defaults.gcp_principal_scope || "user");
    applyValue(gcpRolesInput, (defaults.gcp_roles || []).join(", "));
    applyCheckbox(sshStartTmuxCheckbox, defaults.ssh_start_tmux);
    applyCheckbox(smbCheckbox, defaults.smb_enabled);
    applyCheckbox(vncCheckbox, defaults.vnc_enabled);
    applySelectValue(vncGeometrySelect, defaults.vnc_geometry || "1280x900");
    applySelectValue(vncDepthSelect, defaults.vnc_depth || 24);
  };
  if (mountDataCheckbox && dataPathRow) {
    toggleDataPath = function() {
      var projectMode = projectPathInput && projectPathInput.value.trim() !== "";
      dataPathRow.style.display = mountDataCheckbox.checked && !projectMode && !projectPresetMode ? "" : "none";
    };
    mountDataCheckbox.addEventListener("change", toggleDataPath);
    toggleDataPath();
  }
  if (mountHomeCheckbox && homePathRow) {
    toggleHomePath = function() {
      var projectMode = projectPathInput && projectPathInput.value.trim() !== "";
      homePathRow.style.display = (!mountHomeCheckbox.checked && !projectMode && !projectPresetMode) ? "" : "none";
    };
    mountHomeCheckbox.addEventListener("change", toggleHomePath);
    toggleHomePath();
  }
  if (projectPathInput) {
    syncProjectMode = function() {
      var projectMode = projectPathInput.value.trim() !== "";
      if (projectSelect) {
        projectPresetMode = projectSelect.value !== "";
      }
      projectPathInput.disabled = projectPresetMode;
      if (projectPresetMode) {
        projectPathInput.value = "";
        projectMode = false;
      }
      if (mountHomeCheckbox) {
        mountHomeCheckbox.disabled = projectMode || projectPresetMode;
      }
      if (mountDataCheckbox) {
        mountDataCheckbox.disabled = projectMode || projectPresetMode;
      }
      if (homePathInput) {
        homePathInput.disabled = projectMode || projectPresetMode;
      }
      if (projectMode) {
        if (mountHomeCheckbox) mountHomeCheckbox.checked = false;
        if (mountDataCheckbox) mountDataCheckbox.checked = false;
        if (homePathInput) homePathInput.value = "";
