  if (vncCheckbox && vncOptionsRow) {
    toggleVncOptions = function() {
      vncOptionsRow.style.display = vncCheckbox.checked ? "" : "none";
    };
    vncCheckbox.addEventListener("change", toggleVncOptions);
    toggleVncOptions();
  }
})();
